import { MakeLogicType, afterMount, kea, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { retryWithBackoff } from 'lib/utils/async'


const teamId = window.POSTHOG_APP_CONTEXT?.current_team?.id

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface tracingIngestionLogicValues {
    cachedTeamHasSpans: boolean | null;
    hasSpans: boolean | undefined;
    teamHasSpans: boolean | undefined;
    teamHasSpansCheckFailed: boolean;
    teamHasSpansLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface tracingIngestionLogicActions {
    loadTeamHasSpans: () => any;
    loadTeamHasSpansFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadTeamHasSpansSuccess: (teamHasSpans: boolean, payload?: any) => {
        teamHasSpans: boolean;
        payload?: any;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface tracingIngestionLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        hasSpans: (teamHasSpans: boolean | undefined, cachedTeamHasSpans: boolean | null) => boolean | undefined;
    };
}

export type tracingIngestionLogicType = MakeLogicType<tracingIngestionLogicValues, tracingIngestionLogicActions, Record<string, any>, tracingIngestionLogicMeta>;

export const tracingIngestionLogic = kea<tracingIngestionLogicType>([
    path(['products', 'tracing', 'components', 'SetupPrompt', 'tracingIngestionLogic']),
    loaders({
        teamHasSpans: {
            __default: undefined as boolean | undefined,
            loadTeamHasSpans: async (): Promise<boolean> => {
                return await retryWithBackoff(() => api.tracing.hasSpans(), { maxAttempts: 3 })
            },
        },
    }),

    reducers({
        teamHasSpansCheckFailed: [
            false,
            {
                loadTeamHasSpans: () => false,
                loadTeamHasSpansSuccess: () => false,
                loadTeamHasSpansFailure: () => true,
            },
        ],
        cachedTeamHasSpans: [
            null as boolean | null,
            { persist: true, prefix: `${teamId}__` },
            {
                // Only cache true - spans don't disappear once ingested
                loadTeamHasSpansSuccess: (_, { teamHasSpans }) => teamHasSpans || null,
            },
        ],
    }),

    selectors({
        hasSpans: [
            (s) => [s.teamHasSpans, s.cachedTeamHasSpans],
            (teamHasSpans: boolean | undefined, cachedTeamHasSpans: boolean | null): boolean | undefined => teamHasSpans ?? cachedTeamHasSpans ?? undefined,
        ],
    }),

    afterMount(({ actions, values }) => {
        if (values.cachedTeamHasSpans !== true) {
            actions.loadTeamHasSpans()
        }
    }),
])
